import { describe, it, expect } from "vitest";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

// Mock ModelMessage for testing
const mockModelMessage = {
  role: "user" as const,
  content: "test content",
};

describe("compaction-types", () => {
  describe("Message", () => {
    it("should have required fields", () => {
      const msg: Message = {
        createdAt: new Date("2024-01-01"),
        id: "msg_1",
        modelMessage: mockModelMessage,
      };
      expect(msg.createdAt).toBeInstanceOf(Date);
      expect(msg.id).toBe("msg_1");
      expect(msg.modelMessage).toEqual(mockModelMessage);
    });

    it("should allow optional originalContent field", () => {
      const msg: Message = {
        createdAt: new Date("2024-01-01"),
        id: "msg_1",
        modelMessage: mockModelMessage,
        originalContent: "original text",
      };
      expect(msg.originalContent).toBe("original text");
    });

    it("should work without optional fields", () => {
      const msg: Message = {
        createdAt: new Date("2024-01-01"),
        id: "msg_1",
        modelMessage: mockModelMessage,
      };
      expect(msg.originalContent).toBeUndefined();
    });
  });

  describe("CheckpointMessage", () => {
    it("should have required fields", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: 1234567890,
        id: "checkpoint_1",
        isSummary: false,
        message: mockModelMessage,
      };
      expect(checkpoint.createdAt).toBe(1234567890);
      expect(checkpoint.id).toBe("checkpoint_1");
      expect(checkpoint.isSummary).toBe(false);
      expect(checkpoint.message).toEqual(mockModelMessage);
    });

    it("should allow optional isSummaryMessage field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: 1234567890,
        id: "checkpoint_1",
        isSummary: true,
        isSummaryMessage: true,
        message: mockModelMessage,
      };
      expect(checkpoint.isSummaryMessage).toBe(true);
    });

    it("should allow optional originalContent field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: 1234567890,
        id: "checkpoint_1",
        isSummary: false,
        message: mockModelMessage,
        originalContent: "original",
      };
      expect(checkpoint.originalContent).toBe("original");
    });

    it("should work without optional fields", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: 1234567890,
        id: "checkpoint_1",
        isSummary: false,
        message: mockModelMessage,
      };
      expect(checkpoint.isSummaryMessage).toBeUndefined();
      expect(checkpoint.originalContent).toBeUndefined();
    });
  });

  describe("SessionMetadata", () => {
    it("should have required fields", () => {
      const meta: SessionMetadata = {
        completionTokens: 100,
        createdAt: 1234567890,
        promptTokens: 200,
        sessionId: "session_1",
        summaryMessageId: null,
        updatedAt: 1234567900,
      };
      expect(meta.completionTokens).toBe(100);
      expect(meta.createdAt).toBe(1234567890);
      expect(meta.promptTokens).toBe(200);
      expect(meta.sessionId).toBe("session_1");
      expect(meta.summaryMessageId).toBeNull();
      expect(meta.updatedAt).toBe(1234567900);
    });

    it("should allow non-null summaryMessageId", () => {
      const meta: SessionMetadata = {
        completionTokens: 100,
        createdAt: 1234567890,
        promptTokens: 200,
        sessionId: "session_1",
        summaryMessageId: "summary_msg_1",
        updatedAt: 1234567900,
      };
      expect(meta.summaryMessageId).toBe("summary_msg_1");
    });
  });

  describe("ContinuationVariant", () => {
    it("should accept all valid variants", () => {
      const variants: ContinuationVariant[] = ["manual", "auto-with-replay", "tool-loop"];
      variants.forEach((variant) => {
        expect(variant).toBeDefined();
      });
    });

    it("should only accept valid string values", () => {
      const manual: ContinuationVariant = "manual";
      const autoWithReplay: ContinuationVariant = "auto-with-replay";
      const toolLoop: ContinuationVariant = "tool-loop";

      expect(manual).toBe("manual");
      expect(autoWithReplay).toBe("auto-with-replay");
      expect(toolLoop).toBe("tool-loop");
    });
  });

  describe("CompactionConfig", () => {
    it("should work with empty object (all fields optional)", () => {
      const config: CompactionConfig = {};
      expect(config.contextLimit).toBeUndefined();
      expect(config.enabled).toBeUndefined();
      expect(config.keepRecentTokens).toBeUndefined();
      expect(config.maxTokens).toBeUndefined();
      expect(config.reserveTokens).toBeUndefined();
      expect(config.speculativeStartRatio).toBeUndefined();
      expect(config.summarizeFn).toBeUndefined();
      expect(config.thresholdRatio).toBeUndefined();
    });

    it("should allow all optional fields", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
        enabled: true,
        getStructuredState: () => "state",
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        summarizeFn: async (messages) => "summary",
        thresholdRatio: 0.5,
      };
      expect(config.contextLimit).toBe(128000);
      expect(config.enabled).toBe(true);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.maxTokens).toBe(8000);
      expect(config.reserveTokens).toBe(2000);
      expect(config.speculativeStartRatio).toBe(0.5);
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should allow partial configuration", () => {
      const config: CompactionConfig = {
        enabled: true,
        maxTokens: 5000,
      };
      expect(config.enabled).toBe(true);
      expect(config.maxTokens).toBe(5000);
    });

    it("should accept getStructuredState callback", () => {
      const config: CompactionConfig = {
        getStructuredState: () => "<structured-state>test</structured-state>",
      };
      expect(config.getStructuredState!()).toBe("<structured-state>test</structured-state>");
    });

    it("should accept summarizeFn callback", async () => {
      const config: CompactionConfig = {
        summarizeFn: async (messages, previousSummary) => {
          return `Summary of ${messages.length} messages`;
        },
      };
      const result = await config.summarizeFn!([mockModelMessage], "previous");
      expect(result).toBe("Summary of 1 messages");
    });
